import{_ as e}from"./plugin-vue_export-helper-c27b6911.js";import{o,c as i,f as c}from"./app-d9d82146.js";const n={},l=c('<h3 id="npm与yarn" tabindex="-1"><a class="header-anchor" href="#npm与yarn" aria-hidden="true">#</a> npm与yarn</h3><ol><li>npm早期 <ul><li>npm在安装依赖有层级嵌套问题,如包A有依赖B,那么B安装在A的<code>node_modules</code>文件夹中，B可能也有自己的依赖包C,那么会出现依赖递归或依赖重复下载问题。</li><li>依赖包会出现重复,出现体积过大，内存浪费-&gt;目录层级过深,导致文件路径过长,会出现删除不掉的情况或不好调试的问题。</li></ul></li><li>yarn <ul><li>出现是为了解决问题：npm还没有<code>package-lock.json</code>文件,安装的时候速度很慢,稳定性很差，下载速度慢。</li><li>确定性: 通过yarn.lock；这个文件的依赖版本号不是固定的，结构非json结构，而是一种自定义的标记模式。</li><li>扁平化：安装依赖为模块扁平化方式；将不同版本的依赖包，安装一定的策略归结为单个版本。</li><li>网络性能更好：yarn采用了请求排队的理念,类似于并发池连接；</li><li>采用缓存机制：实现了离线模式</li></ul></li><li>npm和yarn的区别是什么？ <ul><li>yarn是为了弥补npm下载速度慢、版本一致性的问题而产生的。在npm5.4.2版本后，因为竞争关系，他们都支持缓存、扁平化、包并行下载，速度都有明显提升。所有现在的npm和yarn都能选择，他们的性能、优化、缓存都差不多。</li><li>不同的是npm是<code>package-lock.json</code>采用的是JSON的结构，依赖是固定的版本；Yarn是<code>yarn-lock.json</code>，结构是一种自定义的标记方式，子依赖的版本不是固定的版本。</li></ul></li><li>转换:<code>package-lock.json</code>与<code>yarn-lock.json</code>的转换有一个专门的工具<code>synp</code>。</li><li>缺点:解决了嵌套方式的部分问题，但是引入了幽灵依赖的问题，并且同名的包只会提升一个版本的，其余的版本依然会复制多次。</li></ol><h3 id="cnpm、npx和pnpm的区别" tabindex="-1"><a class="header-anchor" href="#cnpm、npx和pnpm的区别" aria-hidden="true">#</a> cnpm、npx和pnpm的区别</h3><ol><li>cnpm：淘宝npm镜像，是淘宝提供的一个npm镜像客户端，默认使用淘宝NPM镜像源<code>（registroy.npmmirror.com）</code>，属于国内的，速度更快。</li><li>npx：是工具包，它不需要全局安装，直接就能运行命令。如果命令的包未安装，那么会临时安装并执行 <ul><li>会在当前目录下的<code>./node_modules/.bin</code>里去查找是否有可执行的命令</li><li>没有找到的话再从全局里查找是否有安装对应的模块</li><li>全局也没有的话就会自动下载对应的模块，用完就删，不会占用本地资源。</li></ul></li><li>pnpm：是一个快速、节省磁盘的包管理工具，原理不是复制包而是通过link,用了软链接。 <ul><li>什么是软链接？硬连接就是同一个文件的不同引用；而软链接是新建一个文件，文件内容指向另一个文件或目录的快捷方式。需要<code>npm link</code>来执行，改变的任何东西，源文件会同步进行变化。</li><li><code>pnpm</code>解决了幽灵依赖，<code>yarn</code>与<code>npm</code>的扁平化处理，会导致明明没有在<code>dependencies</code>声明的依赖A，代码也可以直接<code>require</code>使用，这种不是显式依赖，某天依赖的依赖A直接不被使用，那么代码会有问题。</li></ul></li></ol><h3 id="多包管理" tabindex="-1"><a class="header-anchor" href="#多包管理" aria-hidden="true">#</a> 多包管理</h3><ol><li>多包是指有多个包要管理，比如一个项目有多个业务组件，每个组件都是一个包，手动更新每一个包，（版本号或者具体哪个包）容易出错。<code>Lerna</code>、<code>Yarn Workspaces</code>可以实现多包管理。</li><li>将代码拆分为多个独立的包，可以提高代码的可维护性、复用性和开发效率。</li><li>包（Package）通常是一个独立的模块或功能，包含自己的 package.json 文件。包可以是工具库、组件库或服务等。</li></ol><h4 id="lerna" tabindex="-1"><a class="header-anchor" href="#lerna" aria-hidden="true">#</a> Lerna</h4><ol><li>适合包含多个独立包的大型项目。提供了版本管理、依赖管理、发布等功能。</li><li>实践 <ul><li>初始化项目：<code>npx lerna init</code>，初始化后会生成以下文件：<br> ■ lerna.json：Lerna 配置文件。<br> ■ package.json：根目录的package.json。<br> ■ packages/：用于存放子包的目录。</li><li>创建子包：在<code>packages</code>下创建两个子包，它们都有自己的<code>package.json</code>文件</li><li>配置<code>lerna.json</code>文件</li><li>安装依赖：<code>npx lerna bootstrap</code>，安装所有子包的依赖</li><li>管理依赖：添加公共依赖，<code>npx lerna add lodash</code>；为utils包添加axios，<code>npx lerna add axios --scope=@my-monorepo/utils</code></li><li>运行脚本：运行所有包脚本test，<code>npx lerna run test</code>。运行utils包脚本test， <code>npx lerna run test --scope=@my-monorepo/utils</code></li><li>版本管理：<code>npx lerna version npx lerna publish from-package</code></li></ul></li></ol><h4 id="yarn-workspaces" tabindex="-1"><a class="header-anchor" href="#yarn-workspaces" aria-hidden="true">#</a> Yarn Workspaces</h4><p>a. Yarn 内置的多包管理功能。<br> b. 目前最常见的<code>monorepo</code>解决方案是基于<code>lerna</code>和<code>yarn workspace</code>的<code>monorepo</code>工作流,用yarn来处理依赖问题，用lerna来处理发布问题。<br> c. 实践<br> ⅰ. 初始化项目：在 package.json 中配置 workspaces。<br> ⅱ. 创建子包：在<code>packages</code>目录下创建子包。<br> ⅲ. 安装依赖：<code>yarn install</code>添加所有子包的依赖。<br> ⅳ. 添加依赖：使用 <code>yarn workspace</code>命令为特定包添加依赖。<code>yarn workspace @my-monorepo/utils add axios</code><br> ⅴ. 运行脚本：使用 <code>yarn workspaces run test</code>或<code>yarn workspace @my-monorepo/utils test</code>运行脚本。test是<code>package.json的&quot;scripts&quot;: { &quot;test&quot;: &quot;echo &#39;Running utils tests&#39;&quot;}</code></p><h3 id="优雅的提交" tabindex="-1"><a class="header-anchor" href="#优雅的提交" aria-hidden="true">#</a> 优雅的提交</h3><p>git项目中，通常需要对提交信息（commit message）进行规范化和校验，以确保提交信息的格式符合团队或项目的标准</p><h4 id="commitlint与husky-检测提交信息的规范" tabindex="-1"><a class="header-anchor" href="#commitlint与husky-检测提交信息的规范" aria-hidden="true">#</a> commitlint与husky: 检测提交信息的规范</h4><ol><li><code>&lt;type&gt;(&lt;scope&gt;): &lt;subject&gt;</code>例子：<code>feat(login): add user login feature；fix(api): handle null response</code></li><li>方式一：使用<code>commit-msg</code>钩子校验提交信息，在git项目进入<code>.git/hooks</code>目录，创建<code>commit-msg</code>钩子文件，在<code>commit-msg</code>文件中编写校验逻辑（使用 Bash 和正则表达式），后面提交代码时，如果提交信息不符合规范，提交会被终止。</li><li>方式二：使用<code>commitlint</code>工具自动化校验流程<br> a. 安装commitlint：<code>npm install --save-dev @commitlint/cli @commitlint/config-conventional</code><br> b. 配置commitlint：<code>commitlint.config.js</code> 文件 <code>exports出extends: [&#39;@commitlint/config-conventional&#39;]</code>,<br> c. 配置git钩子：<code>npm install --save-dev husky</code>在在 <code>package.json </code>中添加配置，<code>&quot;scripts&quot;: { &quot;prepare&quot;: &quot;husky install&quot;},&quot;husky&quot;: {&quot;hooks&quot;: {&quot;commit-msg&quot;: &quot;commitlint -E HUSKY_GIT_PARAMS&quot;}} </code><br> d. 命令初始化 <code>husky：npm run prepare</code><br> e. 后面提交不符合规范的提交信息会提示 <code>git commit -m &quot;invalid message&quot;</code></li></ol><h4 id="eslint与lint-staged提交代码前对代码进行静态检查和格式化" tabindex="-1"><a class="header-anchor" href="#eslint与lint-staged提交代码前对代码进行静态检查和格式化" aria-hidden="true">#</a> eslint与lint-staged提交代码前对代码进行静态检查和格式化</h4><ol><li>ESLint负责代码质量检查，而 <code>lint-staged</code> 则只对暂存区（staged）的文件进行检查和修复。</li><li>安装ESLint及其常用插件：<code>npm install --save-dev eslint eslint-plugin-react eslint-config-airbnb</code></li><li>配置ESLint: <code>npx eslint --init</code>初始化后可以修改<code>.eslintrc.js</code>文件自定义Eslint规则。</li><li>安装lint-staged 和 husky：<code>npm install --save-dev lint-staged husky</code></li><li>命令初始化husky：<code>npx husky install &quot;scripts&quot;: {&quot;prepare&quot;: &quot;husky install&quot;}</code></li><li>配置lint-staged：在 package.json 中添加 <code>lint-staged</code>配置：</li></ol>',16),a=[l];function d(t,s){return o(),i("div",null,a)}const m=e(n,[["render",d],["__file","包管理工具以及多包管理.html.vue"]]);export{m as default};
